dtsPropsFor.Button:
/** Visual style of the button. */
  variant?: "default" | "destructive" | "outline" | "secondary" | "ghost" | "link";
  /** Size / shape. `icon*` variants render a square icon-only button. */
  size?: "default" | "xs" | "sm" | "lg" | "icon" | "icon-xs" | "icon-sm" | "icon-lg";
  /** Render as the single child element (Radix Slot) instead of a <button> — e.g. to make a link look like a button. */
  asChild?: boolean;
  children?: React.ReactNode;
  className?: string;
  disabled?: boolean;
  type?: "button" | "submit" | "reset";
  onClick?: React.MouseEventHandler<HTMLButtonElement>;
  /** Also accepts every standard <button> HTML attribute (id, name, form, aria-*, …). */

dtsPropsFor.Badge:
/** Visual style of the badge. */
  variant?: "default" | "secondary" | "destructive" | "outline" | "ghost" | "link";
  /** Render as the single child element (Radix Slot) instead of a <span> — e.g. to make a link-badge. */
  asChild?: boolean;
  children?: React.ReactNode;
  className?: string;
  /** Also accepts every standard <span> HTML attribute. */

dtsPropsFor.Input:
type?: React.HTMLInputTypeAttribute;
  value?: string | number | readonly string[];
  defaultValue?: string | number | readonly string[];
  placeholder?: string;
  disabled?: boolean;
  readOnly?: boolean;
  required?: boolean;
  name?: string;
  onChange?: React.ChangeEventHandler<HTMLInputElement>;
  className?: string;
  /** Also accepts every standard <input> HTML attribute (min, max, step, pattern, aria-*, …). */

dtsPropsFor.Switch:
/** Controlled checked state. */
  checked?: boolean;
  defaultChecked?: boolean;
  onCheckedChange?: (checked: boolean) => void;
  disabled?: boolean;
  required?: boolean;
  name?: string;
  value?: string;
  /** Toggle size. */
  size?: "sm" | "default";
  className?: string;

dtsPropsFor.Table:
children?: React.ReactNode;
